class Solution {
public:
    string getHint(string secret, string guess) {
        int bulls = 0, cows = 0;
        int secretLength = secret.length();
        int guessLength = guess.length();

        if (secretLength != guessLength) {
            return "Error: Secret and guess lengths must be equal";
        }

        for (int i = 0; i < secretLength; i++) {
            if (secret[i] == guess[i]) {
                bulls++;
            } else {
                cows++;
            }
        }

        string hint = bulls + "A" + cows;
        return hint;
    }
};
```

